// Generate 2 thumbnail concepts — LOCKED to single_face style only.
// v4 (2026-05-09): drop dual_face + scene_overlay; A/B variety comes from text_format only
// (stack vs scroll_stopper vs question vs headline). Add scroll_stopper to validFormats so
// Compose Thumbnails' multi-line alternating-color layout is reachable. Single-face always
// renders as: dark text band on the left ~50%, photo on the right ~50%.
var topicArr = $('Fetch Topic').first().json;
var topic = Array.isArray(topicArr) ? topicArr[0] : topicArr;
var topicId = $('Webhook Trigger').first().json.body.topic_id;
var title = topic.seo_title || topic.original_title;
var hook = topic.narrative_hook || '';
var projectId = topic.project_id;
var countryTarget = (topic.country_target || 'GENERAL').toUpperCase();

var projResp = await fetch(
  $env.SUPABASE_URL + '/rest/v1/projects?id=eq.' + projectId + '&select=niche',
  { headers: { 'apikey': $env.SUPABASE_ANON_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY } }
);
var projData = await projResp.json();
var niche = (Array.isArray(projData) && projData[0]) ? projData[0].niche : '';

var registerId = topic.production_register || '';
var registerEra = topic.register_era_detected || '';
var registerGrade = 'teal-orange color grade (Hollywood blockbuster standard)';
var registerAccent = '';
if (registerId) {
  try {
    var rResp = await fetch(
      $env.SUPABASE_URL + '/rest/v1/production_registers?register_id=eq.' + registerId + '&select=config,accent_color_hex',
      { headers: { 'apikey': $env.SUPABASE_ANON_KEY, 'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY } }
    );
    var rData = await rResp.json();
    if (Array.isArray(rData) && rData[0]) {
      registerAccent = rData[0].accent_color_hex || '';
    }
  } catch (e) { /* non-fatal */ }
}
var REGISTER_GRADE_OVERRIDES = {
  REGISTER_01_ECONOMIST: 'muted editorial documentary color grade with controlled warmth, amber midtones, subtle shadow cooling (Johnny Harris / Wendover documentary look)',
  REGISTER_02_PREMIUM: 'Kodak Portra 400 color grade with teal shadows, amber highlights, and generous golden hour warmth (Bloomberg Originals luxury editorial)',
  REGISTER_03_NOIR: 'bleach-bypass desaturated color grade with deep crushed blacks and cold blue shadows, low saturation, noir chiaroscuro (LEMMiNO / Netflix Dirty Money noir)',
  REGISTER_04_SIGNAL: 'clinical cool color grade with blue-black shadows, cyan highlights, and high contrast for tech precision (Apple keynote / ColdFusion tech documentary)',
  REGISTER_05_ARCHIVE: 'sepia-faded warm color grade with lifted shadows, low saturation, and period archival patina (Ken Burns documentary / mid-century Kodachrome)'
};
if (registerId && REGISTER_GRADE_OVERRIDES[registerId]) {
  registerGrade = REGISTER_GRADE_OVERRIDES[registerId];
}

// Per-niche emotion profiles. Only single_a + single_b matter now (dual_*, scene_bg unused).
var nicheEmotions = {
  betrayal_revenge: { single_a: 'jaw-dropped shock, eyes wide, mouth agape, one tear rolling down cheek', single_b: 'cold calculating fury, narrowed eyes, clenched jaw, veins visible on temple', antagonist_kind: 'human' },
  legal_court: { single_a: 'stunned disbelief, wide eyes, raised eyebrows, mouth slightly open', single_b: 'stern suspicious glare, furrowed brows, piercing side-eye, jaw set tight', antagonist_kind: 'human' },
  true_crime: { single_a: 'haunted thousand-yard stare, hollow glistening eyes, single tear, jaw clenched with fierce determination', single_b: 'intense detective scrutiny, one eyebrow raised, skeptical frown, sharp analytical gaze', antagonist_kind: 'human' },
  finance_education: { single_a: 'wide-eyed realization with brows lifted, mouth slightly open, dawning understanding while looking down at a calculator screen showing a meaningful number', single_b: 'confident calm focus with a slight knowing smile, looking directly at camera while holding a small relevant document', antagonist_kind: 'abstract' },
  government_benefits: { single_a: 'wide-eyed quiet realization, hand on chin, eyes scanning a benefits letter, expression that reads as why-didnt-I-know-this', single_b: 'composed quiet determination with a slight smile, holding a benefits card or government letter, looking forward with calm agency', antagonist_kind: 'abstract' },
  transformation: { single_a: 'before-state: drained, hunched, low-energy, looking down with subdued cool lighting', single_b: 'after-state: confident, upright, looking forward with sharp directional warm light and clearer eyes', antagonist_kind: 'abstract' },
  tech_explainer: { single_a: 'curious focused expression, slight head tilt, eyes locked on a glowing screen with cyan-blue rim light', single_b: 'confident knowing slight smile, hand near chin in a thinking pose, sharp directional key light', antagonist_kind: 'abstract' },
  historical_documentary: { single_a: 'thoughtful contemplative expression, hand on chin, soft window light from camera-left, subtle gravitas', single_b: 'stern resolute expression, direct camera gaze, hard directional key light from camera-right, soft fill on shadow side', antagonist_kind: 'human' }
};

var nicheKey = 'historical_documentary';
var nicheLower = (niche || '').toLowerCase();
if (nicheLower === 'super_au' || nicheLower.includes('centrelink') || nicheLower.includes('healthcare card') || nicheLower.includes('aussie super') || nicheLower.includes('australian super') || nicheLower.includes('age pension') || nicheLower.includes('pension loan')) {
  nicheKey = 'government_benefits';
}
else if (nicheLower.includes('credit card') || nicheLower.includes('finance') || nicheLower.includes('money') || nicheLower.includes('wealth') || nicheLower.includes('tax') || nicheLower.includes('investing') || nicheLower.includes('retirement') || nicheLower.includes('budget') || nicheLower.includes('savings')) {
  nicheKey = 'finance_education';
}
else if (nicheLower.includes('legal') || nicheLower.includes('court') || nicheLower.includes('lawsuit')) {
  nicheKey = 'legal_court';
}
else if (nicheLower.includes('crime') || nicheLower.includes('serial') || nicheLower.includes('heist') || nicheLower.includes('unsolved') || nicheLower.includes('cold case')) {
  nicheKey = 'true_crime';
}
else if (nicheLower.includes('betrayal') || nicheLower.includes('scandal') || nicheLower.includes('drama') || nicheLower.includes('divorce') || nicheLower.includes('infidelity')) {
  nicheKey = 'betrayal_revenge';
}
else if (nicheLower.includes('tech') || nicheLower.includes('programming') || nicheLower.includes('coding') || nicheLower.includes('cloud') || nicheLower.includes('aws') || nicheLower.includes('docker') || nicheLower.includes(' ai ') || nicheLower.startsWith('ai ') || nicheLower.endsWith(' ai')) {
  nicheKey = 'tech_explainer';
}
else if (nicheLower.includes('fitness') || nicheLower.includes('weight') || nicheLower.includes('habit') || nicheLower.includes('productivity') || nicheLower.includes('transformation') || nicheLower.includes('learning')) {
  nicheKey = 'transformation';
}
else if (nicheLower.includes('history') || nicheLower.includes('historical') || nicheLower.includes('ancient') || nicheLower.includes('medieval') || nicheLower.includes('archive')) {
  nicheKey = 'historical_documentary';
}
if (countryTarget === 'AU' && (nicheKey === 'betrayal_revenge' || nicheKey === 'legal_court')) {
  if (nicheLower.includes('finance') || nicheLower.includes('super') || nicheLower.includes('centrelink') || nicheLower.includes('benefit') || nicheLower.includes('tax')) {
    nicheKey = 'government_benefits';
  }
}

var emotions = nicheEmotions[nicheKey];
var antagonistKind = emotions.antagonist_kind || 'human';
console.log('Thumbnail concept routing: niche=' + niche + ' country=' + countryTarget + ' -> nicheKey=' + nicheKey + ' antagonist=' + antagonistKind + ' register=' + registerId);

var representationBlock = '';
if (countryTarget === 'AU') {
  representationBlock = ''
    + '   COUNTRY REPRESENTATION (Australia, MANDATORY):\n'
    + '   - Render diverse modern Australian features. Mix subjects across thumbnails: Aboriginal & Torres Strait Islander, Asian-Australian, Pacific Islander, Mediterranean-Australian, and Anglo-Australian heritage.\n'
    + '   - Do NOT default to a generic Western middle-aged white face for every prompt.\n'
    + '   - Do NOT depict any recognizable real Australian politician, judge, MP, AFP officer, ATO commissioner, or other public official.\n'
    + '   - For finance/benefits/super topics, the antagonist is NEVER a person — it is the system, the paperwork, or the rule book.\n\n';
} else if (countryTarget === 'US') {
  representationBlock = ''
    + '   COUNTRY REPRESENTATION (United States, MANDATORY):\n'
    + '   - Render diverse modern American features. Mix subjects across thumbnails: African-American, Latinx, Asian-American, Native American, and white American heritage.\n'
    + '   - Do NOT default to a generic Western middle-aged white face for every prompt.\n'
    + '   - Do NOT depict any recognizable real US politician, judge, federal official, or other public figure.\n\n';
}

var antagonistInstruction = '';
if (antagonistKind === 'abstract') {
  antagonistInstruction = ''
    + '   ANTAGONIST IS ABSTRACT (NOT a person):\n'
    + '   - The single subject must be a sympathetic protagonist (the viewer / a relatable everyday person), NEVER a sinister authority or villain-coded character.\n'
    + '   - Convey the abstract antagonist (paperwork, the system, the rule book) through props or environment, NOT through a hostile human face.\n\n';
} else {
  antagonistInstruction = ''
    + '   ANTAGONIST CHARACTERIZATION:\n'
    + '   - Antagonist may be a human character (per emotion profile) but must be a generic stand-in, NEVER a likeness of a real public figure.\n\n';
}

var promptText = 'You are an elite YouTube thumbnail strategist for documentary channels (12%+ CTR).\n\n'
  + 'VIDEO TITLE: "' + title + '"\n'
  + 'HOOK: "' + hook + '"\n'
  + 'NICHE: "' + niche + '" (resolved profile: ' + nicheKey + ', country: ' + countryTarget + ')\n'
  + 'PRODUCTION REGISTER: ' + (registerId || 'GENERIC') + (registerEra ? ' (' + registerEra + ')' : '') + '\n\n'
  + 'You must generate 2 thumbnail concepts. BOTH concepts MUST use style="single_face".\n\n'
  + 'STYLE (LOCKED):\n'
  + '- "single_face" — One person\'s face filling 65% of RIGHT side of frame. Left half is dark empty negative space reserved for stacked headline text. This is the only style this channel uses.\n\n'
  + 'TEXT FORMAT OPTIONS (the hero text shape — A and B MUST use DIFFERENT formats):\n'
  + '- "stack": punchy 1-3 single-word vertical stack. Each line is ONE word. Best for shocking facts, single concepts, dollar-amount reveals.\n'
  + '- "question": 2-4 line rhetorical question that hooks curiosity. Each line up to 18 chars. Last line MUST end with "?". Best for explainer/educational topics.\n'
  + '- "headline": 1-3 line bold headline phrase, like a magazine cover. Each line up to 22 chars. Best for breaking news, big claims.\n'
  + '- "scroll_stopper": 4-6 line bold headline broken across multiple short lines (each up to 14 chars), with ALTERNATING accent + white words. Total title length 40-55 chars. Best for high-stakes investigative reveals where a longer title is needed and you want maximum scroll-stop. Lines wrap by emphasis word (e.g. "HOW THE / INTERCHANGE / FEE / BECAME / AMERICAS / HIDDEN TAX" — 6 lines alternating yellow + white). PREFERRED for investigative documentary topics.\n\n'
  + 'TEXT WIDTH BUDGET (single_face only — text band is ~480 px wide):\n'
  + '- stack: 1-3 single words ≤ 10 chars each. Safe.\n'
  + '- question: 2-4 lines ≤ 18 chars each. Tight but readable.\n'
  + '- headline: 1-3 lines ≤ 22 chars. Tight; only use for very short headline phrases.\n'
  + '- scroll_stopper: 4-6 lines ≤ 14 chars each. Builds vertical momentum across the dark left band.\n\n'
  + 'FORMAT VARIETY (HARD RULE):\n'
  + '- Concept A and Concept B MUST use DIFFERENT text_format values. The whole point of A/B is to test two different headline approaches against the same single_face layout.\n'
  + '- Recommended pairing for investigative topics: A = "scroll_stopper", B = "stack". For explainer topics: A = "stack", B = "question".\n\n'
  + 'For EACH concept provide a JSON object with these fields:\n\n'
  + '1. style: "single_face" (LOCKED — must always be exactly this string)\n'
  + '2. text_format: "stack" | "question" | "headline" | "scroll_stopper"\n'
  + '3. text_lines: array of strings — the lines as they should appear on the thumbnail, ALL UPPERCASE.\n'
  + '   - stack: 1-3 entries, each ONE word, max 10 chars per line.\n'
  + '   - question: 2-4 entries, each up to 18 chars per line. Last entry MUST end with "?".\n'
  + '   - headline: 1-3 entries, each up to 22 chars per line.\n'
  + '   - scroll_stopper: 4-6 entries, each up to 14 chars per line. Total characters across all lines: 40-55. Break the title at natural emphasis points so alternating-color rendering reads cleanly (every other line is the accent color).\n'
  + '4. emphasis_index: which line gets color emphasis (0-based). For scroll_stopper this is ignored — the renderer alternates accent/white across all lines.\n'
  + '5. image_prompts: array with EXACTLY 1 prompt for the single right-side photo.\n\n'
  + '   IMAGE SIZE: 1280x720 landscape. Subject\'s face is centered at horizontal position 900 of 1280, the entire left 480 pixels are pitch-black empty negative space with NO body parts NO props NO objects.\n\n'
  + '   === CRITICAL: PHOTOREALISTIC IMAGE RULES (MANDATORY) ===\n'
  + '   Every prompt MUST start with: "Ultra-realistic DSLR photograph, candid documentary moment, shot on Canon EOS R5 85mm f/1.2"\n'
  + '   Every prompt MUST end with: "8K resolution, RAW unprocessed photograph, photorealistic, NOT illustration, NOT painting, NOT sketch, NOT anime, NOT digital art, NOT 3D render, NOT cinematic still" followed by the spatial layout enforcement string above.\n\n'
  + '   Skin texture (MANDATORY in every face prompt — explicitly defeats the AI smoothing baseline):\n'
  + '   - Visible skin pores on cheeks, forehead, and nose\n'
  + '   - Stray hair fibers, fine facial hair stubble or peach fuzz visible\n'
  + '   - Subtle natural skin imperfections — moles, fine lines, faint redness — NOT smoothed or airbrushed\n'
  + '   - Skin is NOT plasticized, NOT softened, NOT retouched — documentary unretouched quality\n\n'
  + '   Lighting (MANDATORY in every face prompt):\n'
  + '   - Studio rim lighting from behind creating golden edge light on hair and shoulders\n'
  + '   - Dramatic key light from 45 degrees casting sharp Rembrandt triangle shadow on far cheek\n'
  + '   - Sharp specular catch lights visible in both eyes\n\n'
  + '   Color grade: dark cinematic background with ' + registerGrade + '\n'
  + (registerAccent ? '   Accent color hint (use sparingly in clothing or background prop): ' + registerAccent + '\n' : '')
  + '   Detail: photojournalistic quality, candid moment, NOT a posed studio portrait.\n'
  + '   NO text, NO watermarks, NO logos, NO words of any kind in the image.\n'
  + '   === END PHOTOREALISTIC RULES ===\n\n'
  + representationBlock
  + antagonistInstruction
  + '   === SCENE-IN-CONTEXT (MANDATORY) ===\n'
  + '   The image MUST depict the protagonist INSIDE a specific scene/setting that visually telegraphs what THIS video is about. NOT a generic face on a black studio background.\n'
  + '   - Use the VIDEO TITLE and HOOK to choose the setting. If KEY SEGMENTS are provided, anchor the scene to the most arresting moment from there.\n'
  + '   - Include 2-3 specific environmental details: location (e.g. supermarket aisle, government office, kitchen table, factory floor, pension office), props (receipt, contract, government letter, calculator, security camera, ATM, supermarket trolley), and ambient cues (fluorescent overhead lighting, harsh window light, dim service-counter lamp).\n'
  + '   - The face still fills 65% of the RIGHT side at horizontal position 900 of 1280, but it is shown IN ENVIRONMENT, not against a void.\n'
  + '   - The left 480 pixels remain pitch-black empty negative space (text overlay zone). The environmental detail lives BEHIND and AROUND the face, on the right 800 pixels of the frame.\n'
  + '   KEY SEGMENTS FROM VIDEO (use as scene anchors): ' + (topic.key_segments || '(not available — derive from title/hook)') + '\n\n'
  + '   Emotion guidance for this niche profile (' + nicheKey + '):\n'
  + '   - Concept A subject: ' + emotions.single_a + '\n'
  + '   - Concept B subject: ' + emotions.single_b + '\n\n'
  + 'Return ONLY valid JSON exactly in this shape (both concepts MUST be single_face, MUST have different text_format):\n'
  + '{"concepts":[{"style":"single_face","text_format":"scroll_stopper","text_lines":["HOW THE","INTERCHANGE","FEE","BECAME","HIDDEN","TAX","TODAY"],"emphasis_index":0,"image_prompts":["..."]},{"style":"single_face","text_format":"stack","text_lines":["HIDDEN","TAX"],"emphasis_index":1,"image_prompts":["..."]}]}';

if (countryTarget === 'AU') {
  try {
    var __cbRes = await fetch($env.SUPABASE_URL + '/rest/v1/rpc/render_country_blocks', {
      method: 'POST',
      headers: { apikey: $env.SUPABASE_ANON_KEY, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ p_country_target: 'AU' })
    });
    if (__cbRes.ok) {
      var __cb = await __cbRes.json();
      var __auAppend = [
        __cb.country_compliance_block || '',
        __cb.country_terminology_block || '',
        __cb.country_calendar_context || '',
        __cb.country_demonetization_constraints || ''
      ].filter(Boolean).join('\n\n');
      if (__auAppend) promptText = promptText + '\n\n=== AU COUNTRY CONTEXT ===\n\n' + __auAppend;
    }
  } catch (_) { }
}

var claudeResp = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: { 'x-api-key': $env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
  body: JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 3000, messages: [{ role: 'user', content: promptText }] })
});
var claudeResult = await claudeResp.json();
if (!claudeResult.content || !claudeResult.content[0]) {
  throw new Error('Claude API error: ' + JSON.stringify(claudeResult).substring(0, 500));
}

var concepts;
try {
  var text = claudeResult.content[0].text;
  var jsonMatch = text.match(/\{[\s\S]*\}/);
  concepts = JSON.parse(jsonMatch[0]).concepts;
  if (!concepts || concepts.length < 2) throw new Error('Need 2 concepts');
  // Style is LOCKED to single_face. Coerce anything else.
  var validFormats = ['stack', 'question', 'headline', 'scroll_stopper'];
  var formatLimits = {
    stack: { maxLines: 3, maxChars: 10 },
    question: { maxLines: 4, maxChars: 18 },
    headline: { maxLines: 3, maxChars: 22 },
    scroll_stopper: { maxLines: 6, maxChars: 14 }
  };
  for (var ci = 0; ci < concepts.length; ci++) {
    var c = concepts[ci];
    if (c.style !== 'single_face') {
      console.log('STYLE COERCION: concept ' + ci + ' returned style=' + c.style + ', forcing to single_face.');
      c.style = 'single_face';
    }
    if (!validFormats.includes(c.text_format)) c.text_format = 'stack';
    var lines = c.text_lines || c.text_words || [];
    if (!Array.isArray(lines) || lines.length < 1) throw new Error('Missing text_lines');
    var lim = formatLimits[c.text_format];
    if (lines.length > lim.maxLines) lines = lines.slice(0, lim.maxLines);
    var truncated = false;
    for (var li = 0; li < lines.length; li++) {
      lines[li] = (lines[li] || '').toString().toUpperCase();
      if (lines[li].length > lim.maxChars + 4) { lines[li] = lines[li].substring(0, lim.maxChars); truncated = true; }
    }
    if (truncated) console.log('Variant ' + ci + ': lines truncated to format limit');
    if (c.text_format === 'question') {
      var lastIdx = lines.length - 1;
      if (!lines[lastIdx].endsWith('?')) lines[lastIdx] = lines[lastIdx] + '?';
    }
    c.text_lines = lines;
    c.text_words = lines;
    if (typeof c.emphasis_index !== 'number' || c.emphasis_index >= lines.length) c.emphasis_index = lines.length - 1;
    if (!c.image_prompts || !Array.isArray(c.image_prompts) || c.image_prompts.length < 1) {
      throw new Error('Concept ' + ci + ' missing image_prompts (single_face needs exactly 1).');
    }
    // single_face only ever needs 1 image — drop any extras Claude returns.
    c.image_prompts = c.image_prompts.slice(0, 1);
  }
  // Format variety enforcement (style is already locked, so no style-flip needed).
  if (concepts[0].text_format === concepts[1].text_format) {
    var altF = validFormats.filter(function(f) { return f !== concepts[0].text_format; });
    console.log('FORMAT VARIETY: both concepts have text_format=' + concepts[0].text_format + '. Forcing B to ' + altF[0] + '.');
    concepts[1].text_format = altF[0];
  }
} catch (e) {
  throw new Error('Claude parse error: ' + e.message);
}

console.log('A: style=' + concepts[0].style + ' format=' + concepts[0].text_format + ' lines=' + JSON.stringify(concepts[0].text_lines));
console.log('B: style=' + concepts[1].style + ' format=' + concepts[1].text_format + ' lines=' + JSON.stringify(concepts[1].text_lines));

return [{ json: {
  topic_id: topicId,
  project_id: projectId,
  drive_folder_id: topic.drive_folder_id,
  title: title,
  niche: niche,
  niche_profile_used: nicheKey,
  country_target: countryTarget,
  register_id: registerId,
  register_grade_used: registerGrade,
  concepts: concepts
} }];

// Generate AI thumbnail images via fal.ai Recraft V3 (text-rendering-friendly, $0.04/img).
// v4 (2026-05-09): swap from OpenRouter google/gemini-3-pro-image-preview (402 credit issues)
// to fal-ai/recraft-v3, with fal-ai/ideogram/v2/turbo as fallback. Pattern mirrors
// WF_SCENE_IMAGE_PROCESSOR's text-rendering branch. Recraft returns URLs (not base64),
// so we curl the image to disk before FFmpeg crops to exact target dimensions.
var execSync = require('child_process').execSync;
var data = $input.first().json;
var topicId = data.topic_id;
var concepts = data.concepts;

var workdir = '/tmp/production/' + topicId + '/thumbnails';
execSync('mkdir -p ' + workdir, { shell: '/bin/sh' });

var fontPath = '/tmp/Montserrat-ExtraBold.ttf';
try {
  execSync('test -f ' + fontPath, { shell: '/bin/sh' });
} catch(e) {
  try {
    execSync('curl -sL -o ' + fontPath + ' "https://github.com/JulietaUla/Montserrat/raw/master/fonts/ttf/Montserrat-ExtraBold.ttf"', { shell: '/bin/sh', timeout: 15000 });
  } catch(e2) {
    fontPath = '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf';
  }
}

async function callFal(endpoint, payload, maxRetries) {
  var retries = maxRetries === undefined ? 3 : maxRetries;
  for (var attempt = 1; attempt <= retries; attempt++) {
    var resp = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Authorization': 'Key ' + $env.FAL_API_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    if (resp.ok) {
      var result = await resp.json();
      if (!result.images || !result.images[0] || !result.images[0].url) {
        return { error: { shape: JSON.stringify(result).slice(0, 400) } };
      }
      return { url: result.images[0].url };
    }
    if (resp.status === 429 && attempt < retries) {
      var wait = 2000 * Math.pow(2, attempt - 1) + Math.floor(Math.random() * 1000);
      console.log('  callFal 429 attempt ' + attempt + '/' + retries + ', waiting ' + wait + 'ms');
      await new Promise(function(res) { setTimeout(res, wait); });
      continue;
    }
    var errText = '';
    try { errText = await resp.text(); } catch (_) {}
    return { error: { http: resp.status, body: errText.slice(0, 400) } };
  }
}

function ideogramAspect(t) {
  if (t.w === t.h) return '1:1';
  if (Math.abs(t.w / t.h - 16 / 9) < 0.05) return '16:9';
  if (Math.abs(t.h / t.w - 16 / 9) < 0.05) return '9:16';
  if (Math.abs(t.w / t.h - 4 / 3) < 0.05) return '4:3';
  if (Math.abs(t.h / t.w - 4 / 3) < 0.05) return '3:4';
  return '1:1';
}

// Per-style sizes:
//   falSize is what we ask Recraft to generate (>=1024 on shortest side for quality).
//   target is what FFmpeg crops down to so Compose Thumbnails downstream is unchanged.
var sizeMap = {
  'single_face': [{ falSize: 'landscape_16_9', target: { w: 1280, h: 720 } }],
  'dual_face': [
    { falSize: { width: 1024, height: 1152 }, target: { w: 640, h: 720 } },
    { falSize: { width: 1024, height: 1152 }, target: { w: 640, h: 720 } }
  ],
  'scene_overlay': [
    { falSize: 'landscape_16_9', target: { w: 1280, h: 720 } },
    { falSize: 'square_hd', target: { w: 480, h: 480 } }
  ]
};

console.log('Image gen: provider=fal model=recraft-v3 (with ideogram-v2/turbo fallback)');

var modelsUsed = [];

for (var v = 0; v < 2; v++) {
  var style = concepts[v].style;
  var prompts = concepts[v].image_prompts;
  var sizes = sizeMap[style] || sizeMap['single_face'];
  for (var p = 0; p < prompts.length; p++) {
    var spec = sizes[p] || sizes[0];
    var t = spec.target;
    var promptText = prompts[p];
    console.log('Variant ' + (v === 0 ? 'A' : 'B') + ' img' + p + ' (' + style + '): target=' + t.w + 'x' + t.h);

