    var cropFilter = 'scale=' + t.w + ':' + t.h + ':force_original_aspect_ratio=increase,crop=' + t.w + ':' + t.h;
    execSync('ffmpeg -y -i ' + rawPath + ' -vf "' + cropFilter + '" ' + outPath + ' 2>&1', { shell: '/bin/sh', timeout: 20000 });
