// Compose thumbnails — single_face, diagonal divider, big topic-filling text.
// v5 (2026-05-09): no-spill fix — autoFit now accounts for real Montserrat char width,
// borderw, EMPH_RATIO, AND the diagonal at the text block's bottom. Iterative solver
// converges in 2-3 passes. Diagonal eased to slope -0.083 to leave headroom for long
// emph words like WOOLWORTHS / INTERCHANGE / GOVERNMENT (10-12 chars).
var execSync = require('child_process').execSync;
var data = $input.first().json;
var workdir = data.workdir;
var fontPath = data.fontPath;
var concepts = data.concepts;
var topicId = data.topic_id;

var palettes = [
  { emphasisColor: '0xFFEB00', textColor: '0xFFFFFF', borderColor: '0x000000', dividerColor: '255:235:0' },
  { emphasisColor: '0xFF2020', textColor: '0xFFFFFF', borderColor: '0x000000', dividerColor: '255:32:32' }
];

// Diagonal geometry: top wider, bottom narrower (gentler slope vs v4).
var DIAG_X_TOP = 640;
var DIAG_X_BOT = 580;
var DIAG_LINE_HALFWIDTH = 4;
var DARK_PANEL_RGB = { r: 10, g: 10, b: 22 };

var STYLE_WIDTH = { single_face: 540, dual_face: 1200, scene_overlay: 850 }; // upper bound; iterative solver narrows
var STYLE_HEIGHT = { single_face: 600, dual_face: 380, scene_overlay: 380 };
var CHAR_WIDTH_FACTOR = 0.62;       // Montserrat ExtraBold real glyph factor
var BORDER_BUFFER = 16;             // borderw=7+ rounding for emph lines
var TEXT_X = 40;
var SAFETY_MARGIN = 14;             // extra px between text right edge and diagonal
var FONT_MIN = 55;
var FONT_MAX = 180;
var EMPH_RATIO = 1.10;
var LINE_SPACING_RATIO = 0.14;

function diagXAtY(y) {
  var clamped = Math.max(0, Math.min(720, y));
  return DIAG_X_TOP + (DIAG_X_BOT - DIAG_X_TOP) * clamped / 720;
}

function computeTotalH(fontSize, lines, isScrollStopper, emphIdx) {
  var totalH = 0;
  var emphFontSize = Math.floor(fontSize * EMPH_RATIO);
  var lineSpacing = Math.floor(fontSize * LINE_SPACING_RATIO);
  for (var li = 0; li < lines.length; li++) {
    var isEmph = isScrollStopper ? (li % 2 === 0) : (li === emphIdx);
    totalH += isEmph ? emphFontSize : fontSize;
    if (li < lines.length - 1) totalH += lineSpacing;
  }
  return totalH;
}

function autoFitFontSize(lines, style, isScrollStopper, emphIdx) {
  var maxChars = 0;
  for (var i = 0; i < lines.length; i++) {
    if (lines[i].length > maxChars) maxChars = lines[i].length;
  }
  var availHeight = STYLE_HEIGHT[style] || 380;
  var lineCount = lines.length;
  var lineFactor = lineCount + (lineCount - 1) * LINE_SPACING_RATIO;
  var fromHeight = Math.floor(availHeight / Math.max(0.5, lineFactor));

  // Initial guess from STYLE_WIDTH (upper bound).
  var availWidthInit = STYLE_WIDTH[style] || 850;
  var fromWidthInit = Math.floor((availWidthInit - BORDER_BUFFER) / Math.max(1, maxChars) / CHAR_WIDTH_FACTOR / EMPH_RATIO);
  var fontSize = Math.min(fromWidthInit, fromHeight, FONT_MAX);
  fontSize = Math.max(fontSize, FONT_MIN);

  // Only single_face + scroll_stopper has the diagonal constraint; other styles use the simple fit.
  if (!(isScrollStopper && style === 'single_face')) {
    return fontSize;
  }

  // Iterative solver: at each pass, recompute the available width using the diagonal
  // at the bottom of the rendered text block.
  for (var iter = 0; iter < 3; iter++) {
    var totalH = computeTotalH(fontSize, lines, isScrollStopper, emphIdx);
    var startY = Math.max(40, Math.floor((720 - totalH) / 2));
    var bottomY = startY + totalH;
    var diagAtBottom = diagXAtY(bottomY);
    var availW = diagAtBottom - TEXT_X - SAFETY_MARGIN - BORDER_BUFFER;
    var fromWidth = Math.floor(availW / Math.max(1, maxChars) / CHAR_WIDTH_FACTOR / EMPH_RATIO);
    var newFontSize = Math.min(fromWidth, fromHeight, FONT_MAX);
    newFontSize = Math.max(newFontSize, FONT_MIN);
    if (Math.abs(newFontSize - fontSize) <= 1) {
      fontSize = newFontSize;
      break;
    }
    fontSize = newFontSize;
  }
  return fontSize;
}

for (var v = 0; v < 2; v++) {
  var pal = palettes[v];
  var style = concepts[v].style;
  var lines = concepts[v].text_lines || concepts[v].text_words || [];
  var textFormat = concepts[v].text_format || 'stack';
  var emphIdx = (typeof concepts[v].emphasis_index === 'number') ? concepts[v].emphasis_index : 0;
  if (emphIdx >= lines.length) emphIdx = lines.length - 1;
  var output = workdir + '/thumb_' + (v === 0 ? 'a' : 'b') + '.png';

  var lineCount = lines.length;
  var isScrollStopper = (textFormat === 'scroll_stopper');
  var fontSize = autoFitFontSize(lines, style, isScrollStopper, emphIdx);
  var emphFontSize = Math.floor(fontSize * EMPH_RATIO);
  var lineSpacing = Math.floor(fontSize * LINE_SPACING_RATIO);

  var totalH = computeTotalH(fontSize, lines, isScrollStopper, emphIdx);
  var textStartY;
  if (isScrollStopper && style === 'single_face') {
    textStartY = Math.max(40, Math.floor((720 - totalH) / 2));
  } else {
    textStartY = 720 - totalH - 40;
  }
  var textX = TEXT_X;

  console.log('Variant ' + (v === 0 ? 'A' : 'B') + ': style=' + style + ' format=' + textFormat
    + ' lines=' + lineCount + ' fontSize=' + fontSize + ' totalH=' + totalH + ' startY=' + textStartY
    + ' bottomDiagX=' + Math.round(diagXAtY(textStartY + totalH)));

  // Build base image per style
  var baseImg = workdir + '/base_' + v + '.png';
  if (style === 'single_face') {
    execSync('cp ' + workdir + '/ai_' + v + '_0.png ' + baseImg, { shell: '/bin/sh' });
  } else if (style === 'dual_face') {
    var left = workdir + '/ai_' + v + '_0.png';
    var right = workdir + '/ai_' + v + '_1.png';
    var dualFilter = '[0:v]scale=640:720[l];[1:v]scale=640:720[r];'
      + 'color=c=black:s=1280x720:d=1[bg];'
      + '[bg][l]overlay=0:0[t1];'
      + '[t1][r]overlay=644:0[t2];'
      + '[t2]drawbox=x=638:y=0:w=6:h=720:color=0x0A0A14@1:t=fill,'
      + 'drawbox=x=639:y=0:w=2:h=720:color=0x' + pal.dividerColor.split(':').map(function(c){return ('0'+parseInt(c).toString(16)).slice(-2);}).join('') + '@0.8:t=fill[out]';
    execSync('ffmpeg -y -i ' + left + ' -i ' + right + ' -filter_complex "' + dualFilter + '" -map "[out]" -frames:v 1 ' + baseImg + ' 2>&1', { shell: '/bin/sh', timeout: 30000 });
  } else if (style === 'scene_overlay') {
    var scene = workdir + '/ai_' + v + '_0.png';
    var face = workdir + '/ai_' + v + '_1.png';
    var overlayFilter = '[1:v]scale=360:360[face];'
      + '[0:v][face]overlay=890:330[t1];'
      + '[t1]drawbox=x=888:y=328:w=364:h=364:color=0x' + pal.dividerColor.split(':').map(function(c){return ('0'+parseInt(c).toString(16)).slice(-2);}).join('') + '@0.7:t=2[out]';
    execSync('ffmpeg -y -i ' + scene + ' -i ' + face + ' -filter_complex "' + overlayFilter + '" -map "[out]" -frames:v 1 ' + baseImg + ' 2>&1', { shell: '/bin/sh', timeout: 30000 });
    textX = 40;
  }

  var filters = [];
  if (style === 'scene_overlay') {
    filters.push('drawbox=x=0:y=280:w=850:h=80:color=black@0.15:t=fill');
    filters.push('drawbox=x=0:y=360:w=850:h=80:color=black@0.3:t=fill');
    filters.push('drawbox=x=0:y=440:w=850:h=80:color=black@0.45:t=fill');
    filters.push('drawbox=x=0:y=520:w=850:h=200:color=black@0.6:t=fill');
  } else if (textFormat !== 'scroll_stopper') {
    filters.push('drawbox=x=0:y=302:w=1280:h=72:color=black@0.1:t=fill');
    filters.push('drawbox=x=0:y=374:w=1280:h=72:color=black@0.2:t=fill');
    filters.push('drawbox=x=0:y=446:w=1280:h=72:color=black@0.35:t=fill');
    filters.push('drawbox=x=0:y=518:w=1280:h=202:color=black@0.55:t=fill');
  }

  if (isScrollStopper && style === 'single_face') {
    var slope = (DIAG_X_BOT - DIAG_X_TOP) / 720;
    var slopeStr = slope.toFixed(6);
    var topStr = String(DIAG_X_TOP);
    var hwStr = String(DIAG_LINE_HALFWIDTH);
    var accentR = parseInt(pal.dividerColor.split(':')[0]);
    var accentG = parseInt(pal.dividerColor.split(':')[1]);
    var accentB = parseInt(pal.dividerColor.split(':')[2]);
    function geqExpr(channelName, darkVal, accentVal) {
      var diag = '(' + topStr + '+(' + slopeStr + ')*Y)';
      var leftCond = 'lt(X,' + diag + '-' + hwStr + ')';
      var lineCond = 'lt(abs(X-' + diag + '),' + hwStr + ')';
      var blend = '0.85*' + darkVal + '+0.15*' + channelName + '(X,Y)';
      return 'if(' + leftCond + ',' + blend + ',if(' + lineCond + ',' + accentVal + ',' + channelName + '(X,Y)))';
    }
    var rExpr = geqExpr('r', String(DARK_PANEL_RGB.r), String(accentR));
    var gExpr = geqExpr('g', String(DARK_PANEL_RGB.g), String(accentG));
    var bExpr = geqExpr('b', String(DARK_PANEL_RGB.b), String(accentB));
    filters.push("format=rgb24,geq=r='" + rExpr + "':g='" + gExpr + "':b='" + bExpr + "'");
  }

  var y = textStartY;
  for (var li2 = 0; li2 < lineCount; li2++) {
    var line = lines[li2];
    var isEmph;
    if (isScrollStopper) {
      isEmph = (li2 % 2 === 0);
    } else {
      isEmph = (li2 === emphIdx);
    }
    var fc = isEmph ? pal.emphasisColor : pal.textColor;
    var fs = isEmph ? emphFontSize : fontSize;
    var bw = isEmph ? 7 : 6;
    var safeLine = line.replace(/'/g, '').replace(/:/g, '').replace(/\\/g, '');
    filters.push(
      "drawtext=text='" + safeLine + "'"
      + ":fontfile='" + fontPath + "'"
      + ':fontsize=' + fs
      + ':fontcolor=' + fc
      + ':borderw=' + bw
      + ':bordercolor=' + pal.borderColor
      + ':x=' + textX
      + ':y=' + Math.round(y)
    );
    y += fs + lineSpacing;
  }

  var filterStr = filters.join(',');
  execSync("cat > " + workdir + "/f_" + v + ".txt << 'FEOF'\n" + filterStr + "\nFEOF", { shell: '/bin/sh' });
  execSync('ffmpeg -y -i ' + baseImg + ' -filter_script:v ' + workdir + '/f_' + v + '.txt -frames:v 1 ' + output + ' 2>&1', { shell: '/bin/sh', timeout: 60000 });
  console.log('Thumbnail ' + (v === 0 ? 'A' : 'B') + ' done');
}

