async function callFal(endpoint, payload, maxRetries) {
  var retries = maxRetries === undefined ? 3 : maxRetries;
  for (var attempt = 1; attempt <= retries; attempt++) {
    var resp = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Authorization': 'Key ' + $env.FAL_API_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    if (resp.ok) {
      var result = await resp.json();
      if (!result.images || !result.images[0] || !result.images[0].url) {
        return { error: { shape: JSON.stringify(result).slice(0, 400) } };
      }
      return { url: result.images[0].url };
    }
    if (resp.status === 429 && attempt < retries) {
      var wait = 2000 * Math.pow(2, attempt - 1) + Math.floor(Math.random() * 1000);
      console.log('  callFal 429 attempt ' + attempt + '/' + retries + ', waiting ' + wait + 'ms');
      await new Promise(function(res) { setTimeout(res, wait); });
      continue;
    }
    var errText = '';
    try { errText = await resp.text(); } catch (_) {}
    return { error: { http: resp.status, body: errText.slice(0, 400) } };
  }
}

function ideogramAspect(t) {
  if (t.w === t.h) return '1:1';
  if (Math.abs(t.w / t.h - 16 / 9) < 0.05) return '16:9';
  if (Math.abs(t.h / t.w - 16 / 9) < 0.05) return '9:16';
  if (Math.abs(t.w / t.h - 4 / 3) < 0.05) return '4:3';
  if (Math.abs(t.h / t.w - 4 / 3) < 0.05) return '3:4';
  return '1:1';
}

